#!/usr/bin/env node

/**
 * inject-researched-role-mappings.mjs
 *
 * Takes deep-research role mappings (JSON) and injects them as approved
 * adjudication rows into the pipeline. This bridges the gap between
 * per-company reasoning and the automated scoring pipeline.
 *
 * Usage:
 *   RUN_ID=sp500_2026Q1_v1 node scripts/inject-researched-role-mappings.mjs
 */

import { readdirSync, readFileSync, writeFileSync } from "node:fs";
import path from "node:path";

